BEGIN
INSERT INTO workflow(id, role_id, type_id, before, after, is_allow, condition_type) VALUES(BEEZ.generate_pk_auto('workflow'), #{roleId}, #{typeId}, #{item.beforeCode}, #{item.afterCode}, #{item.isAllow}, #{conditionType});
END;

